def parse_ints(s):
    """Extract all signed integers from string s. Integers may have optional leading + or -. Ignore everything else."""
    integers = []
    current_number = ""
    for char in s:
        if char.isdigit():
            current_number += char
        elif current_number:
            integers.append(int(current_number))
            current_number = ""
        if char == '+' or char == '-':
            if current_number:
                integers.append(int(current_number))
                current_number = ""
            if char == '+':
                current_number = ""
            else:
                current_number = "-"
    if current_number:
        integers.append(int(current_number))
    return integers
